export default function HotelsPage() {
  const [selectedRegion, setSelectedRegion] = useState<Region | null>(null);

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)",
        padding: "2rem",
      }}
    >
      <h1 style={{ fontSize: "2.5rem", textAlign: "center", marginBottom: "2rem", color: "#333" }}>
        Hôtels à Madagascar
      </h1>

      {/* Boutons des régions */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          gap: "1rem",
          justifyContent: "center",
          marginBottom: "2rem",
        }}
      >
        {regionsData.map((region) => (
          <button
            key={region.id}
            onClick={() => setSelectedRegion(region)}
            style={{
              padding: "0.75rem 1.5rem",
              fontSize: "1.1rem",
              backgroundColor: selectedRegion?.id === region.id ? "#0070f3" : "#fff",
              color: selectedRegion?.id === region.id ? "#fff" : "#0070f3",
              border: "2px solid #0070f3",
              borderRadius: "30px",
              cursor: "pointer",
              transition: "all 0.3s",
              fontWeight: "bold",
            }}
            onMouseEnter={(e) => {
              if (selectedRegion?.id !== region.id) {
                e.currentTarget.style.backgroundColor = "#e6f0ff";
              }
            }}
            onMouseLeave={(e) => {
              if (selectedRegion?.id !== region.id) {
                e.currentTarget.style.backgroundColor = "#fff";
              }
            }}
          >
            {region.nom}
          </button>
        ))}
      </div>

      {/* Affichage des hôtels de la région sélectionnée */}
      {selectedRegion && (
        <div>
          <h2 style={{ fontSize: "2rem", marginBottom: "1.5rem", color: "#0070f3" }}>
            {selectedRegion.nom}
          </h2>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
              gap: "1.5rem",
            }}
          >
            {selectedRegion.hotels.map((hotel) => (
              <div
                key={hotel.id}
                style={{
                  backgroundColor: "#fff",
                  borderRadius: "12px",
                  overflow: "hidden",
                  boxShadow: "0 4px 6px rgba(0,0,0,0.1)",
                  transition: "transform 0.3s, box-shadow 0.3s",
                  border: "1px solid #eee",
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = "translateY(-5px)";
                  e.currentTarget.style.boxShadow = "0 10px 20px rgba(0,0,0,0.15)";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = "translateY(0)";
                  e.currentTarget.style.boxShadow = "0 4px 6px rgba(0,0,0,0.1)";
                }}
              >
                {/* Image de l'hôtel */}
                <img
                  src={hotel.image}
                  alt={hotel.nom}
                  style={{
                    width: "100%",
                    height: "180px",
                    objectFit: "cover",
                  }}
                />
                <div style={{ padding: "1.5rem" }}>
                  <h3 style={{ fontSize: "1.3rem", marginBottom: "0.5rem", color: "#333" }}>
                    {hotel.nom}
                  </h3>
                  <p style={{ color: "#666", marginBottom: "0.5rem" }}>{hotel.description}</p>
                  <p style={{ marginBottom: "0.5rem" }}>
                    Note : {"★".repeat(Math.floor(hotel.note))}
                    <span style={{ opacity: 0.5 }}>{"☆".repeat(5 - Math.floor(hotel.note))}</span>
                  </p>
                  <p style={{ fontSize: "0.9rem", color: "#888" }}>{hotel.adresse}</p>
                  <p style={{ fontSize: "0.9rem", color: "#888" }}>Tél : {hotel.telephone}</p>
                  <button
                    style={{
                      width: "100%",
                      marginTop: "1rem",
                      padding: "0.6rem",
                      backgroundColor: "#0070f3",
                      color: "#fff",
                      border: "none",
                      borderRadius: "6px",
                      cursor: "pointer",
                      fontWeight: "bold",
                    }}
                    onClick={() => alert(`Contacter ${hotel.nom} au ${hotel.telephone}`)}
                  >
                    Contacter
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {!selectedRegion && (
        <p style={{ textAlign: "center", color: "#666", fontStyle: "italic" }}>
          Cliquez sur une région pour voir les hôtels disponibles.
        </p>
      )}
    </div>
  );
}